import React, { useEffect, useRef, useState } from 'react';
import { X, RotateCw, Globe, ChevronRight, ChevronLeft, Move, Sun as SunIcon, Database, Crosshair, BarChart3, Radio, Scan, ChevronDown, ChevronUp, Cpu, BookOpen, Map } from 'lucide-react';

declare global {
  interface Window {
    THREE: any;
  }
}

interface Earth3DProps {
  onClose: () => void;
}

const PLANETS_DATA: Record<string, any> = {
  Galaxy: { name: '银河系', type: '星系', tex: 'starmap', size: 3000, dist: 0, speed: 0.00001, color: '#A5B4FC', isGalaxy: true },
  Sun: { name: '太阳', type: '恒星', desc: '太阳系核心，一颗黄矮星，其质量占整个系统的 99.86%。', tex: 'sun', size: 50, dist: 0, speed: 0, color: '#D4A5A5', status: '核聚变反应', isSun: true },
  Mercury: { name: '水星', type: '岩质', desc: '最靠近太阳的行星，大气层极其稀薄，昼夜温差悬殊。', tex: 'mercury', size: 4, dist: 100, speed: 0.008, color: '#B8B0A5', status: '地壳稳定' },
  Venus: { name: '金星', type: '岩质', desc: '太阳系中最热的行星，拥有极厚的高浓度硫酸大气层。', tex: 'venus_surface', size: 6.5, dist: 150, speed: 0.006, color: '#D4A5A5', status: '极度高温' },
  Earth: { name: '地球', type: '生命', desc: '目前已知唯一存在生命的行星，拥有适宜的温度和充足的水分。', tex: 'earth_atmos_2048', size: 7.5, dist: 220, speed: 0.004, color: '#A3B1B7', status: '生态活跃', hasAtmos: true },
  Moon: { name: '月球', type: '卫星', desc: '地球唯一的天然卫星，对地球的潮汐和自转轴稳定性起着关键作用。', tex: 'moon', size: 2, dist: 18, speed: 0.015, color: '#B8B0A5', isMoon: true, parent: '地球' },
  Mars: { name: '火星', type: '岩质', desc: '著名的红色星球，拥有稀薄的大气和太阳系最高的山峰。', tex: 'mars', size: 5.8, dist: 310, speed: 0.0035, color: '#D4A5A5', status: '局部沙尘暴' },
  Jupiter: { name: '木星', type: '气态', desc: '太阳系中体积最大的行星，它是一个巨大的气态巨行星。', tex: 'jupiter', size: 20, dist: 460, speed: 0.002, color: '#B8B0A5', status: '强磁场环境' },
  Saturn: { name: '土星', type: '气态', desc: '以极其显著和壮丽的行星环系统而闻名于世。', tex: 'saturn', size: 17, dist: 640, speed: 0.0015, hasRing: true, color: '#D4A5A5', status: '环系波动' },
  Uranus: { name: '天王星', type: '冰巨', desc: '侧向自转的冰巨星，其自转轴几乎与公转轨道平面平行。', tex: 'uranus', size: 11, dist: 820, speed: 0.001, color: '#A3B1B7', status: '极度低温' },
  Neptune: { name: '海王星', type: '冰巨', desc: '离太阳最远的行星，其大气层中有剧烈风夙。', tex: 'neptune', size: 11, dist: 980, speed: 0.0008, color: '#A3B1B7', status: '超音速风' }
};

const Earth3D: React.FC<Earth3DProps> = ({ onClose }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const initialized = useRef(false);
  const [selectedName, setSelectedName] = useState<string | null>('地球');
  const [isPanelVisible, setIsPanelVisible] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAutoRotating, setIsAutoRotating] = useState(true);

  const engine = useRef({
    scene: null as any,
    camera: null as any,
    renderer: null as any,
    planets: new Map<string, any>(),
    raycaster: null as any,
    mouse: null as any,
    targetName: '地球' as string | null,
    isAutoRotating: true,
    maxAnisotropy: 1,
    vec_targetPos: null as any,
    vec_camPos: null as any,
    controls: {
      theta: 0, phi: Math.PI / 2.5,
      radius: 200, targetRadius: 200,
      isDragging: false,
      lastX: 0, lastY: 0
    }
  });

  const createLabelTexture = (name: string, color: string) => {
    const canvas = document.createElement('canvas');
    canvas.width = 512; canvas.height = 128;
    const ctx = canvas.getContext('2d')!;
    ctx.clearRect(0, 0, 512, 128);
    ctx.font = `bold 64px "Noto Sans SC"`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = '#4A4A4A';
    ctx.fillText(name, 256, 64);
    const tex = new window.THREE.CanvasTexture(canvas);
    return tex;
  };

  useEffect(() => {
    if (initialized.current || !window.THREE || !containerRef.current) return;
    initialized.current = true;
    const THREE = window.THREE;
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0xF5F2EE); // 燕麦色背景
    const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 100000000);
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(window.devicePixelRatio);
    containerRef.current.appendChild(renderer.domElement);
    engine.current.scene = scene;
    engine.current.camera = camera;
    engine.current.renderer = renderer;
    engine.current.raycaster = new THREE.Raycaster();
    engine.current.mouse = new THREE.Vector2();
    engine.current.vec_targetPos = new THREE.Vector3();
    engine.current.vec_camPos = new THREE.Vector3();

    const textureLoader = new THREE.TextureLoader();

    // 环境光和主光源
    scene.add(new THREE.AmbientLight(0xffffff, 0.6));
    const sunLight = new THREE.DirectionalLight(0xffffff, 0.8);
    sunLight.position.set(500, 300, 500);
    scene.add(sunLight);

    Object.keys(PLANETS_DATA).forEach(key => {
      const data = PLANETS_DATA[key];
      if (data.isGalaxy || data.isMoon) return;
      const pivot = new THREE.Group();
      scene.add(pivot);

      const mat = new THREE.MeshStandardMaterial({ 
        color: new THREE.Color(data.color),
        roughness: 0.7,
        metalness: 0.1
      });

      const mesh = new THREE.Mesh(new THREE.SphereGeometry(data.size, 64, 64), mat);
      mesh.position.set(data.dist, 0, 0);
      mesh.userData = { name: data.name };
      pivot.add(mesh);

      textureLoader.load(`https://threejs.org/examples/textures/planets/${data.tex}.jpg`, (t: any) => {
        mat.map = t;
        mat.needsUpdate = true;
      });

      // 莫兰迪风格标签
      const label = new THREE.Sprite(new THREE.SpriteMaterial({ map: createLabelTexture(data.name, data.color), transparent: true }));
      label.scale.set(data.size * 4, data.size, 1);
      label.position.set(0, data.size * 1.5, 0);
      mesh.add(label);

      if (!data.isSun) {
        const orbit = new THREE.LineLoop(
          new THREE.BufferGeometry().setFromPoints(new THREE.EllipseCurve(0, 0, data.dist, data.dist).getPoints(100)),
          new THREE.LineBasicMaterial({ color: 0xB8B0A5, transparent: true, opacity: 0.2 })
        );
        orbit.rotation.x = Math.PI / 2;
        scene.add(orbit);
      }
      engine.current.planets.set(data.name, { pivot, mesh, data });
    });

    const animate = () => {
      const { camera, renderer, scene, planets, targetName, controls, isAutoRotating, vec_targetPos } = engine.current;
      planets.forEach(p => { 
        p.pivot.rotation.y += p.data.speed; 
        p.mesh.rotation.y += 0.002; 
      });
      if (isAutoRotating && !controls.isDragging) controls.theta += 0.001;

      vec_targetPos.set(0, 0, 0);
      if (targetName && planets.has(targetName)) { 
        planets.get(targetName).mesh.getWorldPosition(vec_targetPos); 
      }

      controls.radius = THREE.MathUtils.lerp(controls.radius, controls.targetRadius, 0.08);
      const camX = vec_targetPos.x + controls.radius * Math.sin(controls.phi) * Math.cos(controls.theta);
      const camY = vec_targetPos.y + controls.radius * Math.cos(controls.phi);
      const camZ = vec_targetPos.z + controls.radius * Math.sin(controls.phi) * Math.sin(controls.theta);
      camera.position.lerp(new THREE.Vector3(camX, camY, camZ), 0.1);
      camera.lookAt(vec_targetPos);
      renderer.render(scene, camera);
      requestAnimationFrame(animate);
    };
    animate();
  }, []);

  const handleSelect = (name: string | null) => {
    setSelectedName(name);
    if (name) setIsPanelVisible(true);
    engine.current.targetName = name;
    if (name) {
      const p = Object.values(PLANETS_DATA).find(x => x.name === name);
      engine.current.controls.targetRadius = p ? p.size * 5 : 500;
    }
  };

  const current = Object.values(PLANETS_DATA).find(p => p.name === selectedName);

  return (
    <div ref={containerRef} className="fixed inset-0 bg-morandi-oatmeal z-50 overflow-hidden cursor-grab active:cursor-grabbing text-morandi-charcoal">
      {/* 顶部导航 - 莫兰迪风格 */}
      <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none z-[60] pt-[calc(env(safe-area-inset-top)+1rem)]">
        <div className="bg-white/80 backdrop-blur-xl px-6 py-3 border border-morandi-border rounded-[2rem] pointer-events-auto soft-shadow flex items-center gap-4">
            <div className="w-10 h-10 bg-morandi-blue/20 rounded-xl flex items-center justify-center">
              <Map className="text-morandi-blue" size={20} />
            </div>
            <div>
              <h1 className="text-sm font-bold serif-font text-morandi-charcoal">星空测绘馆</h1>
              <span className="text-[10px] text-morandi-taupe font-medium uppercase tracking-widest">Astro Cartography</span>
            </div>
        </div>
        <button onClick={onClose} className="p-3 bg-white/80 backdrop-blur-md border border-morandi-border hover:bg-morandi-rose hover:text-white transition-all rounded-full pointer-events-auto shadow-sm">
          <X size={20} />
        </button>
      </div>

      {/* 侧边栏 - 星图档案 */}
      <div className={`absolute left-6 top-1/2 -translate-y-1/2 transition-all duration-700 z-[55] ${isSidebarOpen ? 'translate-x-0' : '-translate-x-[calc(100%-1.5rem)]'}`}>
        <div className="flex items-center">
            <div className="w-48 bg-white/80 backdrop-blur-2xl border border-morandi-border rounded-[2.5rem] p-6 flex flex-col pointer-events-auto soft-shadow">
              <div className="text-[10px] font-bold text-morandi-taupe tracking-widest uppercase mb-4 border-b border-morandi-border pb-2">星体索引</div>
              <div className="flex-1 overflow-y-auto no-scrollbar space-y-1">
                {Object.values(PLANETS_DATA).map(p => !p.isMoon && !p.isGalaxy && (
                  <button key={p.name} onClick={() => handleSelect(p.name)} className={`w-full text-left px-4 py-2.5 rounded-xl text-xs font-bold transition-all ${selectedName === p.name ? 'bg-morandi-blue text-white' : 'text-morandi-taupe hover:bg-morandi-blue/10'}`}>
                    {p.name}
                  </button>
                ))}
              </div>
            </div>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-10 h-20 bg-white/80 backdrop-blur-md rounded-r-2xl flex items-center justify-center text-morandi-taupe hover:text-morandi-blue transition-colors pointer-events-auto border border-l-0 border-morandi-border shadow-sm">
              {isSidebarOpen ? <ChevronLeft size={16} /> : <ChevronRight size={16} />}
            </button>
        </div>
      </div>

      {/* 星体详情面板 */}
      {selectedName && current && (
        <div className={`absolute right-6 bottom-24 w-[340px] z-[50] pointer-events-auto transition-all duration-700 ${isPanelVisible ? 'translate-y-0 opacity-100' : 'translate-y-24 opacity-0 pointer-events-none'}`}>
           <div className="bg-white/80 backdrop-blur-3xl border border-morandi-border rounded-[2.5rem] p-8 soft-shadow relative overflow-hidden">
              <button onClick={() => setIsPanelVisible(false)} className="absolute top-4 right-4 text-morandi-taupe hover:text-morandi-charcoal p-2 transition-colors">
                <ChevronDown size={20} />
              </button>
              <div className="flex items-center gap-2 mb-4">
                 <div className="w-2 h-2 rounded-full bg-morandi-sage animate-pulse"></div>
                 <span className="text-[10px] text-morandi-sage font-black uppercase tracking-widest">探测器链路已建立</span>
              </div>
              <h2 className="text-3xl font-bold serif-font mb-4 text-morandi-charcoal">{current.name}</h2>
              <p className="text-morandi-taupe text-sm leading-relaxed mb-6 font-light italic">“{current.desc}”</p>
              <div className="grid grid-cols-2 gap-3">
                <div className="p-4 bg-morandi-oatmeal/50 rounded-2xl border border-morandi-border">
                  <span className="text-[9px] text-morandi-taupe font-bold uppercase block mb-1">星体类型</span>
                  <div className="text-morandi-charcoal text-xs font-bold">{current.type}</div>
                </div>
                <div className="p-4 bg-morandi-oatmeal/50 rounded-2xl border border-morandi-border">
                  <span className="text-[9px] text-morandi-taupe font-bold uppercase block mb-1">当前状态</span>
                  <div className="text-morandi-sage text-xs font-bold">{current.status || '观测中'}</div>
                </div>
              </div>
           </div>
        </div>
      )}

      {/* 底部控制栏 */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-white/80 backdrop-blur-2xl px-10 py-4 border border-morandi-border rounded-full shadow-lg z-[60] pointer-events-auto">
          <button onClick={() => setIsAutoRotating(!isAutoRotating)} className={`flex items-center gap-3 transition-all ${isAutoRotating ? 'text-morandi-blue' : 'text-morandi-taupe hover:text-morandi-charcoal'}`}>
            <RotateCw size={18} className={isAutoRotating ? 'animate-spin' : ''} style={{ animationDuration: '8s' }} />
            <span className="text-[11px] font-bold uppercase tracking-widest">自动环绕</span>
          </button>
          <div className="w-px h-4 bg-morandi-border"></div>
          <button onClick={() => handleSelect(null)} className={`flex items-center gap-3 transition-all ${!selectedName ? 'text-morandi-charcoal' : 'text-morandi-taupe hover:text-morandi-charcoal'}`}>
            <Globe size={18} />
            <span className="text-[11px] font-bold uppercase tracking-widest">概览视角</span>
          </button>
      </div>
    </div>
  );
};

export default Earth3D;

import React, { useState } from 'react';
import { RefreshCw, CheckCircle, ArrowRight, X, Leaf, Info, Sparkles } from 'lucide-react';

interface Organism {
  id: string;
  name: string;
  icon: string;
  role: 'producer' | 'consumer' | 'decomposer';
  description: string;
}

const ORGANISMS: Organism[] = [
  { id: 'grass', name: '草', icon: '🌱', role: 'producer', description: '生产者：通过光合作用制造能量' },
  { id: 'mushroom', name: '蘑菇', icon: '🍄', role: 'decomposer', description: '分解者：分解动植物遗体' },
  { id: 'locust', name: '蝗虫', icon: '🦗', role: 'consumer', description: '初级消费者：以植物为食' },
  { id: 'rabbit', name: '兔子', icon: '🐰', role: 'consumer', description: '初级消费者：喜爱吃草' },
  { id: 'frog', name: '青蛙', icon: '🐸', role: 'consumer', description: '次级消费者：捕食昆虫' },
  { id: 'snake', name: '蛇', icon: '🐍', role: 'consumer', description: '三级消费者：捕食小型动物' },
  { id: 'wolf', name: '狼', icon: '🐺', role: 'consumer', description: '顶级掠食者：捕食草食动物' },
  { id: 'eagle', name: '老鹰', icon: '🦅', role: 'consumer', description: '顶级掠食者：空中捕猎' },
];

const PREDATOR_PREY_MAP: Record<string, string[]> = {
  'grass': ['rabbit', 'locust'],
  'locust': ['frog'],
  'frog': ['snake', 'eagle'],
  'rabbit': ['wolf', 'snake', 'eagle'],
  'snake': ['eagle', 'wolf'],
  'wolf': ['mushroom'],
  'eagle': ['mushroom'],
  'mushroom': ['grass'],
};

const DECOMPOSER_TARGETS = ['grass', 'locust', 'rabbit', 'frog', 'snake', 'wolf', 'eagle'];

const FoodChainApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [chain, setChain] = useState<Organism[]>([]);
  const [feedback, setFeedback] = useState<{ type: 'neutral' | 'success' | 'error', msg: string }>({
    type: 'neutral',
    msg: '请在上方选择生物并添加到逻辑链条中。'
  });
  const [shakingIds, setShakingIds] = useState<number[]>([]);
  const [showEnergyFlow, setShowEnergyFlow] = useState(false);

  const handleAddClick = (organism: Organism) => {
    setChain(prev => [...prev, organism]);
    setFeedback({ type: 'neutral', msg: '已添加节点，请继续构建。' });
    setShowEnergyFlow(false);
  };

  const handleRemove = (index: number) => {
    setChain(prev => prev.filter((_, i) => i !== index));
    setShowEnergyFlow(false);
  };

  const handleReset = () => {
    setChain([]);
    setFeedback({ type: 'neutral', msg: '链条已重置。' });
    setShowEnergyFlow(false);
    setShakingIds([]);
  };

  const handleVerify = () => {
    if (chain.length < 2) {
      setFeedback({ type: 'error', msg: '链条太短，无法形成生态循环。' });
      return;
    }
    if (chain[0].role !== 'producer') {
      setFeedback({ type: 'error', msg: '错误：食物链必须从生产者开始。' });
      setShakingIds([0]);
      return;
    }

    let isValid = true;
    let errorMsg = '';
    const errors: number[] = [];

    for (let i = 0; i < chain.length - 1; i++) {
      const current = chain[i];
      const next = chain[i+1];
      let canEat = false;
      if (next.role === 'decomposer') {
         if (DECOMPOSER_TARGETS.includes(current.id)) canEat = true;
      } else {
         const predators = PREDATOR_PREY_MAP[current.id] || [];
         if (predators.includes(next.id)) canEat = true;
      }
      if (!canEat) {
        isValid = false;
        errors.push(i, i + 1);
        errorMsg = `不匹配：${next.name} 不以 ${current.name} 为食。`;
        break;
      }
    }

    if (isValid) {
      setFeedback({ type: 'success', msg: '构建成功！生态系统运行完美。' });
      setShowEnergyFlow(true);
    } else {
      setFeedback({ type: 'error', msg: errorMsg });
      setShakingIds(errors);
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-morandi-oatmeal flex flex-col font-sans text-morandi-charcoal overflow-hidden">
      <header className="h-20 bg-white/80 backdrop-blur-md border-b border-morandi-border flex items-center justify-between px-8 z-20 shrink-0">
        <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-morandi-sage/20 rounded-2xl flex items-center justify-center border border-morandi-sage/30">
                <Leaf className="text-morandi-sage" size={24} />
            </div>
            <div>
                <h1 className="text-xl font-bold serif-font">自然科学：食物链排序</h1>
                <p className="text-[10px] text-morandi-taupe font-bold uppercase tracking-widest">Ecological Balance Simulation</p>
            </div>
        </div>
        <button onClick={onClose} className="p-3 bg-white hover:bg-morandi-rose hover:text-white rounded-full transition-all border border-morandi-border shadow-sm">
          <X size={20} />
        </button>
      </header>

      <main className="flex-1 flex flex-col p-6 md:p-10 gap-8 overflow-hidden relative">
        <div className="absolute inset-0 watercolor-fill opacity-[0.03] pointer-events-none bg-morandi-sage"></div>

        {/* 生物样本库 */}
        <section className="bg-white/60 backdrop-blur-sm border border-morandi-border p-6 rounded-[2.5rem] soft-shadow shrink-0 overflow-hidden">
          <div className="flex items-center justify-between mb-4 px-2">
            <h2 className="text-xs font-black text-morandi-taupe uppercase tracking-widest flex items-center gap-2">
              <Info size={14} /> 点击添加样本到下方的逻辑槽位
            </h2>
          </div>
          <div className="flex gap-4 overflow-x-auto no-scrollbar pb-2">
            {ORGANISMS.map(org => (
              <button
                key={org.id}
                onClick={() => handleAddClick(org)}
                className="group flex-shrink-0 w-24 h-28 bg-white border border-morandi-border rounded-2xl p-3 flex flex-col items-center justify-center gap-2 transition-all hover:-translate-y-1 hover:border-morandi-sage active:scale-95 shadow-sm"
              >
                <div className="text-4xl group-hover:scale-110 transition-transform">{org.icon}</div>
                <span className="text-xs font-bold text-morandi-charcoal">{org.name}</span>
              </button>
            ))}
          </div>
        </section>

        {/* 构建区 */}
        <div className="flex-1 flex flex-col items-center justify-center gap-8 relative">
          <div className="text-center">
             <h2 className="text-3xl font-bold text-morandi-charcoal serif-font mb-2">生命链条重构</h2>
             <div className={`text-xs font-bold px-6 py-2 rounded-full border transition-all ${
                 feedback.type === 'success' ? 'bg-morandi-sage/20 text-morandi-sage border-morandi-sage' :
                 feedback.type === 'error' ? 'bg-morandi-rose/20 text-morandi-rose border-morandi-rose' :
                 'bg-white text-morandi-taupe border-morandi-border'
             }`}>
                {feedback.msg}
             </div>
          </div>

          <div className="w-full max-w-5xl h-64 bg-white/40 border-2 border-dashed border-morandi-border rounded-[3.5rem] relative flex items-center justify-center p-8 overflow-x-auto no-scrollbar shadow-inner">
             {chain.length === 0 && (
                 <div className="flex flex-col items-center opacity-20 select-none">
                    <Sparkles size={48} className="text-morandi-taupe mb-4" />
                    <p className="text-sm font-bold uppercase tracking-[0.2em]">待构建区域</p>
                 </div>
             )}

             <div className="flex items-center gap-4">
                 {chain.map((item, index) => (
                    <React.Fragment key={`${item.id}-${index}`}>
                        {index > 0 && (
                            <ArrowRight className="text-morandi-border shrink-0" size={24} />
                        )}
                        <div className={`relative w-28 h-36 bg-white border-2 rounded-[2rem] flex flex-col items-center justify-center gap-3 soft-shadow transition-all group ${shakingIds.includes(index) ? 'border-morandi-rose animate-bounce' : 'border-morandi-border hover:border-morandi-sage'}`}>
                            <button 
                                onClick={() => handleRemove(index)}
