                            <div className="text-center">
                                <div className="text-xs font-black">{item.name}</div>
                                <div className="text-[8px] text-morandi-taupe uppercase mt-0.5">{item.role}</div>
                            </div>
                        </div>
                    </React.Fragment>
                 ))}
             </div>
          </div>

          <footer className="flex gap-4">
              <button 
                onClick={handleReset}
                className="px-8 py-4 bg-white border border-morandi-border text-morandi-taupe rounded-2xl font-bold text-sm flex items-center gap-3 transition-all hover:bg-morandi-rose/5"
              >
                  <RefreshCw size={18} /> 重置链条
              </button>
              <button 
                onClick={handleVerify}
                disabled={chain.length < 2}
                className={`px-12 py-4 rounded-2xl font-black flex items-center gap-3 text-base shadow-lg transition-all ${chain.length < 2 ? 'bg-morandi-taupe/20 text-morandi-taupe cursor-not-allowed' : 'bg-morandi-charcoal text-white hover:bg-black active:scale-95'}`}
              >
                  <CheckCircle size={22} /> 运行验证
              </button>
          </footer>
        </div>
      </main>
    </div>
  );
};

