import React, { useState, useEffect, useCallback, useRef } from 'react';
import { X, Play, Zap, Trophy, Timer, RefreshCcw, Sparkles, Brain } from 'lucide-react';

const MathSprintApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [gameState, setGameState] = useState<'idle' | 'playing' | 'result'>('idle');
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(60);
  const [question, setQuestion] = useState({ a: 0, b: 0, op: '+', ans: 0 });
  const [userAns, setUserAns] = useState('');
  const [combo, setCombo] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);

  const generateQuestion = useCallback(() => {
    const a = Math.floor(Math.random() * 90) + 10;
    const b = Math.floor(Math.random() * 80) + 10;
    const op = Math.random() > 0.5 ? '+' : '-';
    let ans = op === '+' ? a + b : a - b;
    if (ans < 0) { 
        setQuestion({ a: b, b: a, op: '-', ans: b - a });
    } else {
        setQuestion({ a, b, op, ans });
    }
    setUserAns('');
  }, []);

  const startGame = () => {
    setScore(0);
    setTimeLeft(60);
    setCombo(0);
    setGameState('playing');
    generateQuestion();
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  useEffect(() => {
    let timer: number;
    if (gameState === 'playing' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(t => t - 1), 1000);
    } else if (timeLeft === 0) {
      setGameState('result');
    }
    return () => clearInterval(timer);
  }, [gameState, timeLeft]);

  const handleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setUserAns(val);
    if (parseInt(val) === question.ans) {
      setScore(s => s + 10 + combo);
      setCombo(c => c + 1);
      generateQuestion();
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-morandi-oatmeal flex flex-col font-sans overflow-hidden text-morandi-charcoal">
      <header className="h-20 bg-white/80 backdrop-blur-md border-b border-morandi-border flex items-center justify-between px-8">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-morandi-blue/20 rounded-2xl flex items-center justify-center border border-morandi-blue/30">
            <Brain className="text-morandi-blue" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold serif-font">逻辑训练：加减速算王</h1>
            <p className="text-[10px] text-morandi-taupe font-bold uppercase tracking-widest">Mental Calculation Challenge</p>
          </div>
        </div>
        <button onClick={onClose} className="p-3 bg-white border border-morandi-border hover:bg-morandi-rose hover:text-white rounded-full transition-all shadow-sm">
          <X size={20} />
        </button>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center p-6 relative">
        <div className="absolute inset-0 watercolor-fill opacity-[0.03] pointer-events-none bg-morandi-blue"></div>

        {gameState === 'idle' && (
          <div className="text-center animate-in zoom-in duration-500 max-w-md w-full bg-white/60 p-12 rounded-[3.5rem] border border-morandi-border soft-shadow">
            <div className="w-24 h-24 bg-morandi-blue rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-lg">
               <Zap size={48} className="text-white fill-current" />
            </div>
            <h2 className="text-3xl font-bold serif-font mb-4">速算修行</h2>
            <p className="text-morandi-taupe font-medium text-sm mb-10 italic leading-relaxed">精准而迅速的判断，是逻辑思维的基石。挑战限时 60 秒内的心算增量。</p>
            <button onClick={startGame} className="w-full py-5 bg-morandi-charcoal text-white font-black text-lg rounded-2xl flex items-center justify-center gap-3 hover:bg-black transition-all active:scale-95 shadow-lg">
              <Play size={20} fill="white" /> 启动挑战
            </button>
          </div>
        )}

        {gameState === 'playing' && (
          <div className="w-full max-w-2xl">
            <div className="flex justify-between items-center mb-12">
               <div className="flex items-center gap-4 px-8 py-4 bg-white/80 rounded-[2rem] border border-morandi-border soft-shadow">
                 <Timer className="text-morandi-rose" size={24} />
                 <span className="text-4xl font-bold serif-font">{timeLeft}s</span>
               </div>
               <div className="text-right">
                 <span className="text-[10px] text-morandi-taupe font-black uppercase tracking-widest block mb-1">当前积分</span>
                 <span className="text-5xl font-black text-morandi-blue italic">{score}</span>
               </div>
            </div>

            <div className="bg-white/80 border-4 border-white rounded-[4rem] p-16 flex flex-col items-center relative soft-shadow border border-morandi-border">
               {combo > 2 && (
                 <div className="absolute -top-6 bg-morandi-rose text-white px-6 py-2 rounded-full font-black italic text-sm animate-bounce shadow-lg flex items-center gap-2">
                   <Sparkles size={16}/> 连击 X{combo}
                 </div>
               )}

               <div className="text-7xl md:text-9xl font-bold serif-font text-morandi-charcoal flex items-center gap-10 mb-12">
                  <span>{question.a}</span>
                  <span className="text-morandi-blue">{question.op}</span>
                  <span>{question.b}</span>
                  <span className="text-morandi-border">=</span>
               </div>

               <input 
                 ref={inputRef}
                 type="number"
                 value={userAns}
                 onChange={handleInput}
                 className="w-full max-w-xs bg-morandi-oatmeal border-none rounded-3xl py-8 text-center text-6xl font-black italic text-morandi-charcoal focus:ring-4 focus:ring-morandi-blue/20 transition-all placeholder:text-morandi-taupe/20 shadow-inner"
                 placeholder="??"
               />
            </div>
          </div>
        )}

        {gameState === 'result' && (
          <div className="text-center animate-in fade-in zoom-in duration-700 bg-white/60 p-12 rounded-[3.5rem] border border-morandi-border soft-shadow max-w-md w-full">
             <Trophy size={80} className="text-morandi-rose mx-auto mb-8 animate-pulse" />
