                 <RefreshCcw size={20}/> 再次开启修行
               </button>
               <button onClick={onClose} className="w-full py-4 bg-white text-morandi-taupe font-bold rounded-2xl border border-morandi-border hover:bg-morandi-oatmeal transition-all">
                 返回节点
               </button>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

