const BrainTeaseApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [teasers, setTeasers] = useState<BrainTease[]>([]);
  const [currentTease, setCurrentTease] = useState<BrainTease | null>(null);
  const [revealedHints, setRevealedHints] = useState<number>(0);
  const [isAnswerRevealed, setIsAnswerRevealed] = useState(false);
  const [mode, setMode] = useState<'DAILY' | 'RANDOM'>('DAILY');
  const [loading, setLoading] = useState(true);

  const fetchTeasers = useCallback(async () => {
    setLoading(true);
    try {
      if (sql) {
        const data = await sql`SELECT * FROM brain_teasers ORDER BY id ASC`;
        if (data && data.length > 0) {
          const formatted = data.map(t => ({
            ...t,
            hints: Array.isArray(t.hints) ? t.hints : JSON.parse(t.hints)
          })) as BrainTease[];
          setTeasers(formatted);
          return formatted;
        }
      }
    } catch (err) { console.warn(err); }
    setTeasers(BRAIN_TEASE_LIBRARY);
    return BRAIN_TEASE_LIBRARY;
  }, []);

  const initGame = useCallback((gameMode: 'DAILY' | 'RANDOM', dataPool: BrainTease[]) => {
    if (dataPool.length === 0) return;
    setIsAnswerRevealed(false);
    setRevealedHints(0);
    setMode(gameMode);

    if (gameMode === 'DAILY') {
      const today = new Date();
      const seed = today.getFullYear() * 10000 + (today.getMonth() + 1) * 100 + today.getDate();
      setCurrentTease(dataPool[seed % dataPool.length]);
    } else {
      setCurrentTease(dataPool[Math.floor(Math.random() * dataPool.length)]);
    }
  }, []);

  useEffect(() => {
    fetchTeasers().then(data => {
      initGame('DAILY', data);
      setLoading(false);
    });
  }, [fetchTeasers, initGame]);

  if (loading) return (
    <div className="fixed inset-0 z-50 bg-morandi-oatmeal flex flex-col items-center justify-center">
      <Loader2 className="w-12 h-12 text-morandi-rose animate-spin mb-4" />
      <p className="text-morandi-taupe text-sm font-bold uppercase tracking-widest">正在联结灵感数据库...</p>
    </div>
  );

  if (!currentTease) return null;

  return (
    <div className="fixed inset-0 z-50 bg-morandi-oatmeal flex flex-col font-sans text-morandi-charcoal overflow-hidden">
      <header className="h-20 bg-white/80 backdrop-blur-md border-b border-morandi-border flex items-center justify-between px-8 z-20 shrink-0">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-morandi-rose/20 rounded-2xl flex items-center justify-center border border-morandi-rose/30">
            <Brain className="text-morandi-rose" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold serif-font">每日趣味：脑筋急转弯</h1>
            <p className="text-[10px] text-morandi-taupe font-bold uppercase tracking-widest">Inspiration & Logic Decoder</p>
          </div>
        </div>
        <button onClick={onClose} className="p-3 bg-white border border-morandi-border hover:bg-morandi-rose hover:text-white rounded-full shadow-sm transition-all">
          <X size={20}/>
        </button>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center p-6 relative">
        <div className="absolute inset-0 watercolor-fill opacity-[0.03] pointer-events-none bg-morandi-rose"></div>

        <div className="w-full max-w-3xl space-y-8">
          {/* 题目卡片 */}
          <div className="bg-white/90 border border-morandi-border rounded-[3rem] p-12 soft-shadow relative overflow-hidden group">
             <div className="absolute -top-10 -right-10 opacity-[0.05] group-hover:rotate-12 transition-transform duration-1000">
               <Brain size={240} />
             </div>
             <div className="flex items-center gap-2 mb-8">
               <span className="px-3 py-1 bg-morandi-oatmeal border border-morandi-border text-[10px] font-black text-morandi-taupe rounded-full tracking-widest uppercase">ID: {currentTease.id}</span>
               <div className="flex gap-1.5 ml-auto">
                 {[...Array(3)].map((_, i) => (
                   <div key={i} className={`w-2 h-2 rounded-full ${i < (currentTease.difficulty === 'EASY' ? 1 : currentTease.difficulty === 'MEDIUM' ? 2 : 3) ? 'bg-morandi-rose' : 'bg-morandi-border'}`}></div>
                 ))}
               </div>
             </div>
             <h2 className="text-3xl md:text-5xl font-bold serif-font leading-relaxed text-morandi-charcoal min-h-[160px]">
               {currentTease.question}
             </h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* 提示区 */}
            <div className="bg-white/60 backdrop-blur-sm border border-morandi-border rounded-[2.5rem] p-8">
              <h3 className="text-xs font-black text-morandi-taupe uppercase tracking-widest flex items-center gap-2 mb-6">
                <Key size={14} className="text-morandi-rose" /> 解密锦囊 ({revealedHints}/{currentTease.hints.length})
              </h3>
              <div className="space-y-4">
                {currentTease.hints.map((hint, idx) => (
                  <div key={idx} className="transition-all duration-500">
                    {revealedHints > idx ? (
                      <div className="bg-morandi-rose/5 border border-morandi-rose/10 p-4 rounded-2xl text-sm text-morandi-charcoal italic animate-in slide-in-from-left">
                        {hint}
                      </div>
                    ) : (
                      <button 
                        onClick={() => setRevealedHints(idx + 1)}
                        disabled={revealedHints !== idx}
                        className="w-full bg-white border border-morandi-border p-4 rounded-2xl text-xs font-bold text-morandi-taupe flex items-center justify-between hover:bg-morandi-oatmeal transition-all disabled:opacity-50"
                      >
                        <span className="flex items-center gap-2"><Lock size={14} /> 开启锦囊 {idx + 1}</span>
                        <Zap size={12} className="text-morandi-rose" />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* 答案与操作 */}
            <div className="flex flex-col gap-4">
              <div className={`flex-1 bg-white/60 backdrop-blur-sm border rounded-[2.5rem] p-10 flex flex-col items-center justify-center text-center transition-all duration-700 ${isAnswerRevealed ? 'border-morandi-sage' : 'border-morandi-border'}`}>
                {!isAnswerRevealed ? (
