                  >
                    揭开谜底
                  </button>
                ) : (
                  <div className="animate-in zoom-in duration-500">
                    <div className="text-[10px] font-black text-morandi-sage uppercase tracking-widest mb-4 flex items-center justify-center gap-2">
                      <Unlock size={14} /> 逻辑链路已闭合
                    </div>
                    <p className="text-2xl font-bold serif-font text-morandi-charcoal leading-relaxed italic">
                      {currentTease.answer}
                    </p>
                  </div>
                )}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => initGame('RANDOM', teasers)}
                  className="py-5 bg-white border border-morandi-border rounded-2xl flex items-center justify-center gap-3 transition-all hover:bg-morandi-oatmeal"
                >
                  <RefreshCw size={18} className="text-morandi-rose" />
                  <span className="text-xs font-bold text-morandi-charcoal">下一关</span>
                </button>
                <button 
                  onClick={() => { alert("已复制到剪贴板！"); }}
                  className="py-5 bg-white border border-morandi-border rounded-2xl flex items-center justify-center gap-3 transition-all hover:bg-morandi-oatmeal"
                >
                  <Share2 size={18} className="text-morandi-blue" />
                  <span className="text-xs font-bold text-morandi-charcoal">分享</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="h-10 bg-white/50 px-8 flex items-center justify-between text-[10px] font-bold text-morandi-taupe uppercase tracking-widest italic shrink-0">
        <div className="flex gap-6">
          <span className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-morandi-rose rounded-full animate-pulse"></div> 连接稳定</span>
          <span>Records: {teasers.length} Entries</span>
        </div>
        <div>V3.5 Hand-drawn Edition</div>
      </footer>
    </div>
  );
};

