    const sunLight = new THREE.DirectionalLight(0xffffff, 0.8);
    sunLight.position.set(500, 300, 500);
    scene.add(sunLight);

    Object.keys(PLANETS_DATA).forEach(key => {
      const data = PLANETS_DATA[key];
      if (data.isGalaxy || data.isMoon) return;
      const pivot = new THREE.Group();
      scene.add(pivot);

      const mat = new THREE.MeshStandardMaterial({ 
        color: new THREE.Color(data.color),
        roughness: 0.7,
        metalness: 0.1
      });

      const mesh = new THREE.Mesh(new THREE.SphereGeometry(data.size, 64, 64), mat);
      mesh.position.set(data.dist, 0, 0);
      mesh.userData = { name: data.name };
      pivot.add(mesh);

      textureLoader.load(`https://threejs.org/examples/textures/planets/${data.tex}.jpg`, (t: any) => {
        mat.map = t;
        mat.needsUpdate = true;
      });

      // 莫兰迪风格标签
      const label = new THREE.Sprite(new THREE.SpriteMaterial({ map: createLabelTexture(data.name, data.color), transparent: true }));
      label.scale.set(data.size * 4, data.size, 1);
      label.position.set(0, data.size * 1.5, 0);
      mesh.add(label);

      if (!data.isSun) {
        const orbit = new THREE.LineLoop(
          new THREE.BufferGeometry().setFromPoints(new THREE.EllipseCurve(0, 0, data.dist, data.dist).getPoints(100)),
          new THREE.LineBasicMaterial({ color: 0xB8B0A5, transparent: true, opacity: 0.2 })
        );
        orbit.rotation.x = Math.PI / 2;
        scene.add(orbit);
      }
      engine.current.planets.set(data.name, { pivot, mesh, data });
    });

    const animate = () => {
      const { camera, renderer, scene, planets, targetName, controls, isAutoRotating, vec_targetPos } = engine.current;
      planets.forEach(p => { 
        p.pivot.rotation.y += p.data.speed; 
        p.mesh.rotation.y += 0.002; 
      });
      if (isAutoRotating && !controls.isDragging) controls.theta += 0.001;

      vec_targetPos.set(0, 0, 0);
      if (targetName && planets.has(targetName)) { 
        planets.get(targetName).mesh.getWorldPosition(vec_targetPos); 
      }

      controls.radius = THREE.MathUtils.lerp(controls.radius, controls.targetRadius, 0.08);
      const camX = vec_targetPos.x + controls.radius * Math.sin(controls.phi) * Math.cos(controls.theta);
      const camY = vec_targetPos.y + controls.radius * Math.cos(controls.phi);
      const camZ = vec_targetPos.z + controls.radius * Math.sin(controls.phi) * Math.sin(controls.theta);
      camera.position.lerp(new THREE.Vector3(camX, camY, camZ), 0.1);
      camera.lookAt(vec_targetPos);
      renderer.render(scene, camera);
      requestAnimationFrame(animate);
    };
    animate();
  }, []);

  const handleSelect = (name: string | null) => {
    setSelectedName(name);
    if (name) setIsPanelVisible(true);
    engine.current.targetName = name;
    if (name) {
      const p = Object.values(PLANETS_DATA).find(x => x.name === name);
      engine.current.controls.targetRadius = p ? p.size * 5 : 500;
    }
  };

  const current = Object.values(PLANETS_DATA).find(p => p.name === selectedName);

  return (
    <div ref={containerRef} className="fixed inset-0 bg-morandi-oatmeal z-50 overflow-hidden cursor-grab active:cursor-grabbing text-morandi-charcoal">
      {/* 顶部导航 - 莫兰迪风格 */}
      <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none z-[60] pt-[calc(env(safe-area-inset-top)+1rem)]">
        <div className="bg-white/80 backdrop-blur-xl px-6 py-3 border border-morandi-border rounded-[2rem] pointer-events-auto soft-shadow flex items-center gap-4">
            <div className="w-10 h-10 bg-morandi-blue/20 rounded-xl flex items-center justify-center">
              <MapIcon className="text-morandi-blue" size={20} />
            </div>
            <div>
              <h1 className="text-sm font-bold serif-font text-morandi-charcoal">星空测绘馆</h1>
              <span className="text-[10px] text-morandi-taupe font-medium uppercase tracking-widest">Astro Cartography</span>
            </div>
        </div>
        <button onClick={onClose} className="p-3 bg-white/80 backdrop-blur-md border border-morandi-border hover:bg-morandi-rose hover:text-white transition-all rounded-full pointer-events-auto shadow-sm">
          <X size={20} />
        </button>
      </div>

      {/* 侧边栏 - 星图档案 */}
      <div className={`absolute left-6 top-1/2 -translate-y-1/2 transition-all duration-700 z-[55] ${isSidebarOpen ? 'translate-x-0' : '-translate-x-[calc(100%-1.5rem)]'}`}>
        <div className="flex items-center">
            <div className="w-48 bg-white/80 backdrop-blur-2xl border border-morandi-border rounded-[2.5rem] p-6 flex flex-col pointer-events-auto soft-shadow">
              <div className="text-[10px] font-bold text-morandi-taupe tracking-widest uppercase mb-4 border-b border-morandi-border pb-2">星体索引</div>
              <div className="flex-1 overflow-y-auto no-scrollbar space-y-1">
                {Object.values(PLANETS_DATA).map(p => !p.isMoon && !p.isGalaxy && (
                  <button key={p.name} onClick={() => handleSelect(p.name)} className={`w-full text-left px-4 py-2.5 rounded-xl text-xs font-bold transition-all ${selectedName === p.name ? 'bg-morandi-blue text-white' : 'text-morandi-taupe hover:bg-morandi-blue/10'}`}>
                    {p.name}
                  </button>
                ))}
              </div>
            </div>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-10 h-20 bg-white/80 backdrop-blur-md rounded-r-2xl flex items-center justify-center text-morandi-taupe hover:text-morandi-blue transition-colors pointer-events-auto border border-l-0 border-morandi-border shadow-sm">
              {isSidebarOpen ? <ChevronLeft size={16} /> : <ChevronRight size={16} />}
            </button>
        </div>
      </div>

      {/* 星体详情面板 */}
      {selectedName && current && (
        <div className={`absolute right-6 bottom-24 w-[340px] z-[50] pointer-events-auto transition-all duration-700 ${isPanelVisible ? 'translate-y-0 opacity-100' : 'translate-y-24 opacity-0 pointer-events-none'}`}>
           <div className="bg-white/80 backdrop-blur-3xl border border-morandi-border rounded-[2.5rem] p-8 soft-shadow relative overflow-hidden">
              <button onClick={() => setIsPanelVisible(false)} className="absolute top-4 right-4 text-morandi-taupe hover:text-morandi-charcoal p-2 transition-colors">
                <ChevronDown size={20} />
              </button>
              <div className="flex items-center gap-2 mb-4">
                 <div className="w-2 h-2 rounded-full bg-morandi-sage animate-pulse"></div>
                 <span className="text-[10px] text-morandi-sage font-black uppercase tracking-widest">探测器链路已建立</span>
              </div>
              <h2 className="text-3xl font-bold serif-font mb-4 text-morandi-charcoal">{current.name}</h2>
              <p className="text-morandi-taupe text-sm leading-relaxed mb-6 font-light italic">“{current.desc}”</p>
              <div className="grid grid-cols-2 gap-3">
                <div className="p-4 bg-morandi-oatmeal/50 rounded-2xl border border-morandi-border">
                  <span className="text-[9px] text-morandi-taupe font-bold uppercase block mb-1">星体类型</span>
                  <div className="text-morandi-charcoal text-xs font-bold">{current.type}</div>
                </div>
                <div className="p-4 bg-morandi-oatmeal/50 rounded-2xl border border-morandi-border">
                  <span className="text-[9px] text-morandi-taupe font-bold uppercase block mb-1">当前状态</span>
                  <div className="text-morandi-sage text-xs font-bold">{current.status || '观测中'}</div>
                </div>
              </div>
           </div>
        </div>
      )}

      {/* 底部控制栏 */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-white/80 backdrop-blur-2xl px-10 py-4 border border-morandi-border rounded-full shadow-lg z-[60] pointer-events-auto">
          <button onClick={() => setIsAutoRotating(!isAutoRotating)} className={`flex items-center gap-3 transition-all ${isAutoRotating ? 'text-morandi-blue' : 'text-morandi-taupe hover:text-morandi-charcoal'}`}>
            <RotateCw size={18} className={isAutoRotating ? 'animate-spin' : ''} style={{ animationDuration: '8s' }} />
            <span className="text-[11px] font-bold uppercase tracking-widest">自动环绕</span>
          </button>
          <div className="w-px h-4 bg-morandi-border"></div>
          <button onClick={() => handleSelect(null)} className={`flex items-center gap-3 transition-all ${!selectedName ? 'text-morandi-charcoal' : 'text-morandi-taupe hover:text-morandi-charcoal'}`}>
            <Globe size={18} />
            <span className="text-[11px] font-bold uppercase tracking-widest">概览视角</span>
          </button>
      </div>
    </div>
  );
};

