  imageUrl: string;
  description: string;
  tags: string[];
  icon?: string; // 新增可选图标属性
}

import React from 'react';
import { AppItem } from '../types';
import { MoreHorizontal } from 'lucide-react';
import { motion } from 'framer-motion';

interface AppCardProps {
  item: AppItem;
  onClick: (item: AppItem) => void;
}

const AppCard: React.FC<AppCardProps> = ({ item, onClick }) => {
  // 更加细致的色彩映射，参考您提供的 iOS 极简设计
  const getTheme = () => {
    const title = item.title;
    const tags = item.tags;

    // 地理/科学 -> 灰蓝色
    if (tags.includes('地理') || item.icon === 'public' || item.icon === 'science') {
      return { bg: 'bg-[#B0BEC5]', iconColor: 'text-white/80', icon: item.icon || 'public' };
    }
    // 数学/逻辑 -> 浅黄色
    if (tags.includes('数学') || item.icon === 'functions' || item.icon === 'lightbulb') {
      return { bg: 'bg-[#FFE082]', iconColor: 'text-yellow-700/80', icon: item.icon || 'functions' };
    }
    // 国学/文化 -> 浅绿色
    if (tags.includes('国学') || tags.includes('文化') || item.icon === 'menu_book') {
      return { bg: 'bg-[#A5D6A7]', iconColor: 'text-green-700/80', icon: item.icon || 'menu_book' };
    }

    // 默认 -> 燕麦色/中性
    return { 
      bg: item.category === 'education' ? 'bg-morandi-blue/20' : 
          item.category === 'entertainment' ? 'bg-morandi-rose/20' : 'bg-morandi-sage/20',
      iconColor: 'text-morandi-charcoal/60',
      icon: item.icon || 'auto_awesome_motion'
    };
  };

  const theme = getTheme();

  return (
    <motion.div 
      initial={{ opacity: 0, y: 10 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      whileTap={{ scale: 0.98 }}
      className="group relative bg-white rounded-ios overflow-hidden border border-morandi-border soft-shadow transition-all hover:bg-white cursor-pointer mb-4"
      onClick={() => onClick(item)}
    >
      <div className="flex p-5 gap-6 items-center">
        {/* iOS 风格图标容器 - 完美适配参考截图 */}
        <div className={`w-20 h-20 md:w-24 md:h-24 flex-shrink-0 rounded-[1.8rem] flex items-center justify-center shadow-sm relative overflow-hidden ${theme.bg}`}>
          {/* 背景装饰（模仿参考图中的微弱渐变或线条感） */}
          <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-transparent opacity-50"></div>
          <span className={`material-icons-outlined text-4xl md:text-5xl relative z-10 ${theme.iconColor}`}>
            {theme.icon}
          </span>
          {/* 装饰圆圈 */}
          <div className="absolute w-12 h-12 border border-white/10 rounded-full -top-2 -right-2"></div>
        </div>

        {/* 右侧信息 */}
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-start mb-1">
            <h4 className="text-lg font-bold text-morandi-charcoal truncate tracking-tight serif-font">
              {item.title}
            </h4>
            <button className="text-slate-200 hover:text-morandi-taupe transition-colors">
              <MoreHorizontal size={20} />
            </button>
          </div>
          <p className="text-slate-400 text-xs leading-relaxed mb-3 font-medium line-clamp-2 italic">
            {item.description}
          </p>
          <div className="flex gap-2">
            <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest bg-slate-50 text-slate-300 border border-slate-100`}>
              {item.category.toUpperCase()}
            </span>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default AppCard;

